/* Count strings per first character (lower‑case) */
void firstLetterCounts(std::vector<std::string> const& s,
                       std::array<std::size_t, 26>& bins) {
    // Zero the output array
    bins.fill(0);

    /* Use a per‑thread local buffer to avoid false sharing. */
    constexpr std::size_t ALPHA = 26;
#pragma omp parallel
    {
        std::array<std::size_t, ALPHA> local{};
        local.fill(0);

#pragma omp for schedule(static)
        for (std::size_t i = 0; i < s.size(); ++i) {
            /* Each string is guaranteed to start with a lower‑case letter. */
            const unsigned char c = static_cast<unsigned char>(s[i][0] - 'a');
            local[c] += 1;
        }

        /* Merge local results into the global bins.  The merge is
           performed per thread but the critical section is very small
           because it only touches the output array. */
#pragma omp critical
        {
            for (std::size_t k = 0; k < ALPHA; ++k) {
                bins[k] += local[k];
            }
        }
    }
