#pragma once
#include <vector>
#include <omp.h>

struct Element {
    size_t index;
    double value;
};

/*
 * Compute z = alpha * x + y where x and y are sparse vectors.
 * The result is accumulated into the existing vector z.
 * The function is thread‑safe and preserves the exact semantics of the
 * reference implementation.
 */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
    /* Process the x vector in parallel */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        const size_t idx = x[i].index;
        const double inc = alpha * x[i].value;
        /* Atomic add to avoid race conditions on z[idx] */
        #pragma omp atomic
        z[idx] += inc;
    }

    /* Process the y vector in parallel */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        const size_t idx = y[i].index;
        /* Atomic add to avoid race conditions on z[idx] */
        #pragma omp atomic
        z[idx] += y[i].value;
    }
}
