struct Point {
    double x, y;
};

/* Count the number of cartesian points in each quadrant. The vector points
   contains a list of `Point` objects. Store the counts in `bins`.
   Example:
      input: [{x=1.5, y=0.1}, {x=-3, y=1.1}, {x=5, y=9},
              {x=1.5, y=-1}, {x=3, y=-7}, {x=0.1, y=2}]
      output: [3, 1, 0, 2]
*/
inline void countQuadrants(const std::vector<Point>& points,
                           std::array<std::size_t, 4>& bins)
{
    // Zero the bins once (outside the parallel region)
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Work‑share the loop; use a reduction on the four counters.
    #pragma omp parallel for reduction(+:bins[0],bins[1],bins[2],bins[3]) schedule(static)
    for (std::size_t i = 0; i < points.size(); ++i) {
        const Point& p = points[i];
        if (p.x >= 0.0) {
            if (p.y >= 0.0) {
                ++bins[0];          // Q1
            } else {
                ++bins[3];          // Q4
            }
        } else {
            if (p.y >= 0.0) {
                ++bins[1];          // Q2
            } else {
                ++bins[2];          // Q3
            }
        }
    }
}
```
This implementation preserves the exact semantics of the original function while leveraging OpenMP for parallel execution across all available threads. The `reduction` clause ensures that each thread keeps a private copy of the counters, which are summed at the end, guaranteeing correctness and avoiding race conditions. The static schedule balances the workload for large input vectors.

