```cpp
#pragma once
#include <vector>
#include <cstdint>
#include <algorithm>
#include <omp.h>

/* Return the number of vertices in the largest component of the graph defined by the adjacency matrix A.
   A is an NxN adjacency matrix stored in row‑major.               */
int largestComponent(std::vector<int> const& A, size_t N)
{
    // visited 0 = not seen, 1 = seen
    std::vector<uint8_t> visited(N, 0);

    int largest = 0;

    // 8 threads maximum for this machine – let OpenMP decide best scheduling
    #pragma omp parallel
    {
        std::vector<int> stack;            // stack for iterative DFS
        int local_max = 0;                 // best component found by this thread

        #pragma omp for schedule(dynamic)
        for (int start = 0; start < static_cast<int>(N); ++start)
        {
            if (omp_atomic_compare_and_exchange(&visited[start], 0, 1))
            {
                // start new component
                stack.clear();
                stack.push_back(start);
                int count = 0;

                while (!stack.empty())
                {
                    int v = stack.back();
                    stack.pop_back();
                    ++count;

                    // iterate neighbours
                    const int base = v * static_cast<int>(N);
                    for (int u = 0; u < static_cast<int>(N); ++u)
                    {
                        if (A[base + u] && !omp_atomic_compare_and_exchange(&visited[u], 0, 1))
                        {
                            stack.push_back(u);
                        }
                    }
                }
                local_max = std::max(local_max, count);
            }
        }

        // combine local maxima
        #pragma omp atomic
        largest = std::max(largest, local_max);
    }

    return largest;
}
