#pragma once
#include <cstdint>
#include <vector>
#include <numeric>
#include <algorithm>
#include <execution>

// Parallel inclusive scan implementation: 2‑phase prefix sum
// (block‐level scan + adjustment).  Uses OpenMP directives
// for parallelism and standard library functions for correctness.

inline void prefixSum(const std::vector<int64_t> &x, std::vector<int64_t> &output) {
    const std::size_t n = x.size();
    if (n == 0) return;

    output.resize(n);

    // Phase 1 – local block scans
    const std::size_t block = 1 << 13; // tune for cache size (~8 KB)
    std::vector<int64_t> blockSums((n + block - 1) / block, 0);

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < blockSums.size(); ++i) {
        const std::size_t start = i * block;
        const std::size_t end   = std::min(start + block, n);
        int64_t sum = 0;
        for (std::size_t j = start; j < end; ++j) {
            sum = (sum += x[j]);          // inclusive scan
            output[j] = sum;
        }
        blockSums[i] = sum;
    }

    // Phase 2 – propagate block sums
    std::vector<int64_t> add(blockSums.size(), 0);
    // prefix sum of blockSums (exclusive)
    std::exclusive_scan(blockSums.begin(), blockSums.end(), add.begin(), int64_t{0});

    // add block offsets to each element
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < n; ++i) {
        output[i] += add[i / block];
    }
}
