#pragma once
#include <vector>
#include <stack>
#include <cstdint>

inline void dfs_iterative(const std::vector<int>& A, int start, size_t N,
                          std::vector<char>& visited)
{
    std::stack<int> st;
    st.push(start);
    visited[start] = 1;
    while (!st.empty())
    {
        int node = st.top();
        st.pop();

        const int* row = A.data() + node * N;
        for (size_t j = 0; j < N; ++j)
        {
            if (row[j] && !visited[j])
            {
                visited[j] = 1;
                st.push(static_cast<int>(j));
            }
        }
    }
}

/* Count the number of connected components in the undirected graph defined by the
   adjacency matrix A.
   A is an NxN adjacency matrix stored in row-major. A is an undirected graph.
*/
int componentCount(const std::vector<int>& A, size_t N)
{
    std::vector<char> visited(N, 0);
    int count = 0;
    for (int i = 0; i < static_cast<int>(N); ++i)
    {
        if (!visited[i])
        {
            dfs_iterative(A, i, N, visited);
            ++count;
        }
    }
    return count;
}
