          std::vector<double> const& x,
          double beta,
          std::vector<double>& y,
          size_t M, size_t N)
{
    /* Fast local references to the underlying arrays. */
    double* yptr = y.data();
    const double* xptr = x.data();
    const COOElement* aptr = A.data();
    const size_t a_size = A.size();

    /* Scale the output vector by beta in parallel. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        yptr[i] *= beta;
    }

    /* Accumulate COO contributions.  The bounds checks in the original
     * code are preserved for correctness, but the condition is evaluated
     * in a single branch under OpenMP.  The check is inexpensive and
     * rarely triggers. */
    #pragma omp parallel for schedule(static, 8192)
    for (size_t i = 0; i < a_size; ++i) {
        const COOElement& e = aptr[i];
        if (e.row < M && e.column < N) {
            /* Use atomic addition to avoid race conditions,
             * but only when overlapping rows occur.  The typical
             * sparse pattern has few collisions; thus the
             * performance penalty is minimal. */
            #pragma omp atomic
            yptr[e.row] += alpha * e.value * xptr[e.column];
        }
    }
}
