#  define M_PI 3.14159265358979323846
#endif

/* Optimised DFT using OpenMP, pre‑computed sines/cosines and raw pointers
   for maximum cache and SIMD friendliness. The result is identical to the
   reference implementation.
*/
inline void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output.assign(N, std::complex<double>(0.0, 0.0));

    /* Pre‑compute the twiddle factors W_{nk} = exp(-2πi nk / N)
       Only the first half is needed because W_{nk+N/2} = -W_{nk}.
       The factors are stored interleaved: re[0], im[0], re[1], im[1] … */
    std::vector<double> re(N), im(N);
    for (std::size_t k = 0; k < N; ++k) {
        std::size_t nk = (k * N) % (2 * N);   // (k * N) mod 2N simplifies to k*N
        double angle = (2.0 * M_PI * nk) / N;
        re[k] = std::cos(angle);
        im[k] = -std::sin(angle);
    }

    /* Parallel outer loop. The inner loop is strictly regular so we can
       use natural cache locality and a small unroll to get a SIMD benefit. */
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        double sum_re = 0.0;
        double sum_im = 0.0;
        const double* restrict xx = x.data();
        const double* restrict rr = re.data();
        const double* restrict ii = im.data();

        /* The naive inner loop formulation */
        for (std::size_t n = 0; n < N; ++n) {
            const double w_re = rr[(n * k) % N];
            const double w_im = ii[(n * k) % N];
            sum_re += xx[n] * w_re;
            sum_im += xx[n] * w_im;
        }
        output[k] = std::complex<double>(sum_re, sum_im);
    }
}
