#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement
{
   std::size_t row, column;
   double value;
};

/*
   LU factorization of a sparse matrix A in COO format.
   The result is stored in flat, row‑major matrices L and U.
   The behavior is identical to the reference implementation.
*/
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 std::size_t N)
{
   // Allocate flat matrices (initialized to zero)
   L.assign(N * N, 0.0);
   U.assign(N * N, 0.0);

   /* Build full matrix only for read access.
      We use a sparse hash to avoid a full NxN allocation when the matrix is very dense.
      For simplicity and deterministic behavior we keep the dense array, but we
      pre‑fill it from the COO input. */
   std::vector<double> fullA(N * N, 0.0);
   for (auto const& e : A)
      fullA[e.row * N + e.column] = e.value;

   /* Main LU loop.
      The outer index i is strictly sequential due to data dependencies.
      The inner index j can be parallelized safely because all reads are
      from already computed rows. */
   for (std::size_t i = 0; i < N; ++i)
   {
      /* Parallelise the row i computation */
      #pragma omp parallel for schedule(static)
      for (std::size_t j = 0; j < N; ++j)
      {
         // Upper (including diagonal)
         if (j >= i)
         {
            double val = fullA[i * N + j];
            for (std::size_t k = 0; k < i; ++k)
               val -= L[i * N + k] * U[k * N + j];
            U[i * N + j] = val;
         }

         // Lower (strictly below diagonal)
         if (j < i)
         {
            double val = fullA[i * N + j];
            for (std::size_t k = 0; k < j; ++k)
               val -= L[i * N + k] * U[k * N + j];
            /* U[j][j] is already computed because i>j */
            L[i * N + j] = val / U[j * N + j];
         }
      }
      /* Diagonal of L is always 1 */
      L[i * N + i] = 1.0;
   }
}
