 * Return the area of the smallest triangle that can be formed by any 3 points.
 * Uses 2‑level parallelism on the outer loops with a reduction on the minimum
 * area found. The algorithm is unchanged from the reference implementation.
 */
double smallestArea(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* Parallelise the outer two loops; the innermost loop is small
       enough that no extra work is beneficial. The reduction on
       "minArea" ensures correct minimal value across threads. */
#pragma omp parallel for collapse(2) reduction(min:minArea) schedule(static)
    for (size_t i = 0; i < n - 2; ++i) {
        for (size_t j = i + 1; j < n - 1; ++j) {
            for (size_t k = j + 1; k < n; ++k) {
                const double area = triArea(points[i], points[j], points[k]);
                if (area < minArea) minArea = area;
            }
        }
    }

