 *   z becomes [2, -6, 5, 17]
 */
inline void axpy(double alpha, const std::vector<double> &x,
                 const std::vector<double> &y, std::vector<double> &z) {
    const std::size_t n = x.size();
    if (n != y.size() || n != z.size()) {
        // For safety: if sizes mismatch, do nothing.  
        // The harness guarantees equal sizes, so this is a no-op.
        return;
    }

    /* Parallelize the loop.  
     * The work is embarrassingly parallel and memory bound,
     * so we let OpenMP divide the vector into chunks.
     * Each iteration does a single multiply and addition,
     * which keeps CPU registers busy and allows efficient
     * SIMD usage by the compiler.
     */
#pragma omp parallel for schedule(static, 1024)
    for (std::size_t i = 0; i < n; ++i) {
        z[i] = alpha * x[i] + y[i];
    }
