/* Compute one iteration of a 3‑point 1D Jacobi stencil.
   Each element of `input` is averaged with its two neighbours
   and written into `output`. Missing neighbours are treated as zero.
*/
inline void jacobi1D(std::vector<double> const& input, std::vector<double> &output)
{
    const std::size_t n = input.size();
    if (n == 0) return;                       // nothing to do

    // Ensure output has the same size as input
    if (output.size() != n) output.resize(n);

    /*---  The first element  -------------------------------------------------
      output[0] = (0 + input[0] + input[1])/3
    */
    if (n > 1) {
        output[0] = (input[0] + input[1]) / 3.0;
    } else {
        output[0] = input[0] / 3.0;
    }

    /*---  Interior elements  -------------------------------------------------
      Run the bulk of the loop in parallel with block tiling to keep the
      working set small and improve cache reuse.
    */
#pragma omp parallel for schedule(static, 8192)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        const double sum = input[i - 1] + input[i] + input[i + 1];
        output[i] = sum / 3.0;
    }

    /*---  The last element  --------------------------------------------------
      output[n‑1] = (input[n-2] + input[n-1] + 0)/3
    */
    if (n > 1) {
        output[n - 1] = (input[n - 2] + input[n - 1]) / 3.0;
    }
}
