#pragma once
#include <vector>
#include <cmath>
#include <algorithm>

struct COOElement {
    size_t row, column;
    double value;
};

/*
   Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double>& x,
                       size_t N)
{
    // Flattened dense matrix in row-major order
    std::vector<double> mat(N * N, 0.0);
    for (const auto& e : A)
        mat[e.row * N + e.column] = e.value;

    x.assign(N, 0.0);
    std::vector<double> rhs = b;          // copy of b
    std::vector<double> pivot(N, 0.0);    // for swap row to reduce cache misses

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // Find pivot row
        size_t maxRow = i;
        double maxVal = std::fabs(mat[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double v = std::fabs(mat[k * N + i]);
            if (v > maxVal) {
                maxVal = v;
                maxRow = k;
            }
        }

        // Swap rows if necessary
        if (maxRow != i) {
            for (size_t j = 0; j < N; ++j)
                std::swap(mat[i * N + j], mat[maxRow * N + j]);
            std::swap(rhs[i], rhs[maxRow]);
        }

        // Eliminate rows below
        double pivotVal = mat[i * N + i];
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -mat[k * N + i] / pivotVal;
            for (size_t j = i; j < N; ++j) {
                if (j == i)
                    mat[k * N + j] = 0.0;
                else
                    mat[k * N + j] += factor * mat[i * N + j];
            }
            rhs[k] += factor * rhs[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = rhs[i];
        for (size_t j = i + 1; j < N; ++j)
            sum -= mat[i * N + j] * x[j];
        x[i] = sum / mat[i * N + i];
    }
}
