            const int   down  = (i + 1 < N)   ? input[(i + 1) * N + j] : 0;
            const int   left  = (j > 0)       ? input[i * N + j - 1]    : 0;
            const int   right = (j + 1 < N)   ? input[i * N + j + 1]    : 0;
