/* 5‑point 2D Jacobi stencil
 * inputs:
 *   - input  : NxN grid (row‑major)
 *   - output : buffer to collect results (row‑major)
 *
 * Each element is replaced with the average of itself and its
 * four orthogonal neighbours (out‑of‑bounds neighbours contribute 0).
 */
void jacobi2D(std::vector<double> const& input,
              std::vector<double>& output,
              std::size_t N)
{
    const double div5 = 1.0 / 5.0;
    const double* in  = input.data();
          double* out = output.data();

    /* Parallelise over all grid points.  The nested loops are collapsed
     * so that the outermost dimension is split among threads while
     * the innermost loop still accesses contiguous memory, keeping
     * cache pressure low.
     */
#pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t base = i * N;          // starting index of row i
        std::size_t prev = (i > 0) ? (i - 1) * N : 0;  // row above
        std::size_t next = (i + 1 < N) ? (i + 1) * N : 0; // row below

        for (std::size_t j = 0; j < N; ++j)
        {
            double sum = in[base + j];    // centre

            if (i > 0)          sum += in[prev + j];   // north
            if (i + 1 < N)      sum += in[next + j];   // south
            if (j > 0)          sum += in[base + j - 1]; // west
            if (j + 1 < N)      sum += in[base + j + 1]; // east

            out[base + j] = sum * div5;
        }
    }
}
