void partialMinimums(std::vector<float> &x) {
    const std::size_t N = x.size();
    if (N == 0) return;

    const int T = omp_get_max_threads();
    const std::size_t chunk = (N + T - 1) / T;          // may be larger than N

    std::vector<float> tmp(N);
    std::vector<float> thread_min(T, std::numeric_limits<float>::max());

    /* 1st pass: compute local inclusive minima and the last value of each chunk */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, N);
        if (start >= N) return;

        float cur_min = std::numeric_limits<float>::max();
        for (std::size_t i = start; i < end; ++i) {
            cur_min = (x[i] < cur_min) ? x[i] : cur_min;
            tmp[i] = cur_min;
        }
        thread_min[tid] = cur_min;       // last value of this thread's chunk
    }

    /* 2nd pass: compute global prefix minima of thread minima */
    std::vector<float> prefix_min(T);
    float acc = std::numeric_limits<float>::max();
    for (int t = 0; t < T; ++t) {
        acc = (thread_min[t] < acc) ? thread_min[t] : acc;
        prefix_min[t] = acc;
    }

    /* 3rd pass: add preceding prefix minima to each chunk */
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, N);
        if (start >= N) return;

        /* value to subtract from this chunk to get original inclusive minima */
        float bias = (tid == 0) ? std::numeric_limits<float>::max() : prefix_min[tid - 1];
        for (std::size_t i = start; i < end; ++i) {
            /* tmp[i] already contains local min; we need min of all previous chunks
               i.e. min(tmp[i], bias). Since bias is the minimum up to the previous
               chunk, the inclusive min up to i is min(tmp[i], bias). */
            x[i] = (tmp[i] < bias) ? tmp[i] : bias;
        }
    }
}
