#include <vector>
#include <algorithm>

struct Point { double x, y; };

namespace detail {
    // inline cross product for speed
    inline double cross(const Point& a, const Point& b, const Point& c)
    {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    }
}

void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    const size_t n = points.size();
    if (n < 3) { hull = points; return; }

    // make a copy that can be sorted
    std::vector<Point> sorted(points);
    // sort by x, then y
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    std::vector<Point> ans;
    ans.reserve(2 * n);            // avoid re‑allocations
    size_t k = 0;

    // lower hull
    for (size_t i = 0; i < n; ++i) {
        while (k >= 2 &&
               detail::cross(ans[k-2], ans[k-1], sorted[i]) <= 0.0) {
            --k;
        }
        ans[k++] = sorted[i];
    }

    // upper hull
    for (size_t i = n; i-- > 0; ) {
        while (k >= (size_t)(n + 1) &&
               detail::cross(ans[k-2], ans[k-1], sorted[i]) <= 0.0) {
            --k;
        }
        ans[k++] = sorted[i];
    }

    ans.resize(k-1);          // last point is same as first
    hull = std::move(ans);
}
