/*
 * Compute the rank (index in the sorted order) of each element of `x`.
 * The result is stored in `ranks_`.
 *
 * This implementation uses OpenMP to parallelise the final assignment
 * of ranks. Sorting is still performed with std::sort, which is
 * efficient and guaranteed to give stable results for the intended
 * behaviour.
 */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_)
{
    // Sanity check – the caller must provide a vector of the correct size
    ranks_.resize(x.size());

    // Build an index vector and sort it according to the values in `x`
    std::vector<size_t> indices(x.size());
    std::iota(indices.begin(), indices.end(), 0);
    std::sort(indices.begin(), indices.end(), [&x](size_t i1, size_t i2)
    {
        return x[i1] < x[i2];
    });

    // Parallel assignment of ranks – each thread operates on a separate
    // slice of the indices vector, so there are no data races.
    #pragma omp parallel for
    for (int i = 0; i < static_cast<int>(indices.size()); ++i)
    {
        ranks_[indices[i]] = static_cast<size_t>(i);
    }
}
