inline bool xorContains(const std::vector<int> &x, const std::vector<int> &y, int val) {
    const int *xs = x.data(), *ys = y.data();
    const std::size_t xs_size = x.size();
    const std::size_t ys_size = y.size();

    bool foundInX = false;
    for (std::size_t i = 0; i < xs_size; ++i) {
        if (*xs++ == val) {
            foundInX = true;
            break;
        }
    }

    bool foundInY = false;
    for (std::size_t i = 0; i < ys_size; ++i) {
        if (*ys++ == val) {
            foundInY = true;
            break;
        }
    }

    return foundInX ^ foundInY;
}
