inline int findKthSmallest(std::vector<int> const& x, int k) {
    // kth is 1‑based, convert to 0‑based index
    const int idx = k - 1;
    // Work on a copy to preserve the original vector
    std::vector<int> tmp(x.begin(), x.end());

    // nth_element partitions the vector so that the element at
    // index `idx` is the element that would be there if the
    // vector were fully sorted. Average linear time.
    std::nth_element(tmp.begin(), tmp.begin() + idx, tmp.end());

    // The element of interest is now at position `idx`
    return tmp[idx];
}
