#pragma once
#include <vector>
#include <algorithm>
#include <cmath>

struct Point { double x, y; };

inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline double dist(const Point& a, const Point& b) {
    return std::hypot(b.x - a.x, b.y - a.y); // more accurate than sqrt(pow(...))
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points. */
double convexHullPerimeter(const std::vector<Point>& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    // Work on a copy sorted by (x, y)
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    // The convex hull will be stored in ans
    std::vector<Point> ans;
    ans.reserve(2 * n);                // avoid reallocations

    // --- lower hull ---
    for (size_t i = 0; i < n; ++i) {
        while (ans.size() >= 2 &&
               cross(ans[ans.size() - 2], ans[ans.size() - 1], pts[i]) <= 0)
            ans.pop_back();
        ans.push_back(pts[i]);
    }

    // --- upper hull ---
    size_t lowerSize = ans.size();
    for (size_t i = n - 1; i > 0; --i) {
        while (ans.size() > lowerSize + 1 &&
               cross(ans[ans.size() - 2], ans[ans.size() - 1], pts[i - 1]) <= 0)
            ans.pop_back();
        ans.push_back(pts[i - 1]);
    }

    // last point of upper hull is same as first of lower hull; drop it
    if (!ans.empty()) ans.pop_back();

    // Compute perimeter
    double perimeter = 0.0;
    const size_t m = ans.size();
    for (size_t i = 0; i < m; ++i)
        perimeter += dist(ans[i], ans[(i + 1) % m]);

    return perimeter;
}
