// Counts the number of doubles in `x` that have fractional parts in
// [0,0.25), [0.25,0.5), [0.5,0.75), [0.75,1) and stores the result in `bins`.
// The result is identical to the original algorithm but uses
// a branch‑less mapping and OpenMP parallelism for speed.
inline void countQuartiles(std::vector<double> const& x,
                            std::array<std::size_t, 4>& bins)
{
    // Ensure the output array starts from zero
    bins.fill(0);

    // Thread–local arrays for reduction
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 4>> thread_bins(nthreads);
    for (int t = 0; t < nthreads; ++t)
        thread_bins[t].fill(0);

    #pragma omp parallel
    {
        int t = omp_get_thread_num();
        std::array<std::size_t, 4>& local = thread_bins[t];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            // Truncate towards zero to get the integer part
            double frac = x[i] - static_cast<long>(x[i]);

            // Map the fractional part to an index 0..3
            // (-0.999... gives 0, 0.0 gives 0, 0.249... gives 0, etc.)
            std::size_t idx = static_cast<std::size_t>(frac * 4.0);
            if (idx > 3) idx = 3;   // safety for floating‑point errors
            ++local[idx];
        }
    }

    // Reduce locally computed counts into the final result
    for (int t = 0; t < nthreads; ++t) {
        for (int j = 0; j < 4; ++j)
            bins[j] += thread_bins[t][j];
    }
}
