size_t findClosestToPi(const std::vector<double> &x) {
    // Guard against an empty vector – the original code assumes at least one element.
    if (x.empty()) return std::size_t(-1);

    // Use OpenMP to find the minimum distance in parallel.
    // Each thread keeps its own local best and then the global best is merged
    // outside the parallel loop.
    constexpr double PI = M_PI;
    std::size_t best_idx = 0;
    double best_diff = std::abs(x[0] - PI);

    #pragma omp parallel
    {
        double local_best_diff = best_diff;
        std::size_t local_best_idx = best_idx;

        #pragma omp for nowait
        for (std::size_t i = 1; i < x.size(); ++i) {
            double diff = std::abs(x[i] - PI);
            if (diff < local_best_diff) {
                local_best_diff = diff;
                local_best_idx = i;
            }
        }

        // Merge local results into the global result
        #pragma omp critical
        {
            if (local_best_diff < best_diff) {
                best_diff = local_best_diff;
                best_idx = local_best_idx;
            }
        }
    }

    return best_idx;
}
