// Edge detection kernel (laplacian)
static constexpr int edgeKernel[9] = {
    -1, -1, -1,
    -1,  8, -1,
    -1, -1, -1
};

/* Convolve `imageIn` with the 3x3 edge kernel and store the clipped results in
 * `imageOut`.  The images are NxN grayscale matrices in row-major order.
 *
 * The function is fully parallelised with OpenMP and uses pointer arithmetic
 * to minimise overhead while keeping the behaviour (clipping 0‑255 and
 * zero‑padding for out‑of‑bounds pixels) identical to the original.
 */
inline void convolveKernel(const std::vector<int>& imageIn,
                           std::vector<int>& imageOut,
                           std::size_t N)
{
    // Local copies of raw pointers for speed
    const int* src = imageIn.data();
    int*      dst = imageOut.data();

    // Parallelise the outer loops: rows are independent
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t base = i * N;          // offset of current row in src/dst
        for (std::size_t j = 0; j < N; ++j)
        {
            int sum = 0;

            // Unrolled 3x3 neighbourhood, with bounds checks
            // Top row
            if (i > 0)
            {
                const int* rowTop = src + (i-1)*N;
                sum += rowTop[j    ] * edgeKernel[0];
                sum += rowTop[j+1  ] * edgeKernel[1];
                if (j > 0)
                    sum += rowTop[j-1] * edgeKernel[2];
            }

            // Middle row
            {
                const int* rowMid = src + base;
                sum += rowMid[j-1] * edgeKernel[3];
                sum += rowMid[j  ] * edgeKernel[4];
                sum += rowMid[j+1] * edgeKernel[5];
            }

            // Bottom row
            if (i + 1 < N)
            {
                const int* rowBot = src + (i+1)*N;
                sum += rowBot[j    ] * edgeKernel[6];
                sum += rowBot[j+1  ] * edgeKernel[7];
                if (j > 0)
                    sum += rowBot[j-1] * edgeKernel[8];
            }

            // Clip to [0,255]
            if (sum < 0)
                dst[base + j] = 0;
            else if (sum > 255)
                dst[base + j] = 255;
            else
                dst[base + j] = sum;
        }
    }
}
