/* Return the index of the first even number in the vector x.
   Returns x.size() when no even number is found. */
size_t findFirstEven(std::vector<int> const& x)
{
    // Use raw pointer for a tiny speed boost and enable loop
    // unrolling to help the compiler generate vectorised code.
    const int* data = x.data();
    const size_t n    = x.size();

    // Process blocks of 8 elements for better branch prediction.
    size_t i = 0;
    const size_t block = 8;
    for (; i + block <= n; i += block) {
        // Check each element in the block; break early if found.
        for (size_t j = 0; j < block; ++j) {
            if ((data[i + j] & 1) == 0) { // use bitwise test for evenness
                return i + j;
            }
        }
    }

    // Handle the remaining elements.
    for (; i < n; ++i) {
        if ((data[i] & 1) == 0) {
            return i;
        }
    }

    return n; // no even number found
}
