#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <limits>
#include <omp.h>

struct Point {
    double x, y;
};

/* O(n log n) closest-pair using divide‑and‑conquer.  */
static double dist(const Point& a, const Point& b) {
    double dx = a.x - b.x, dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

static double closest_pair_rec(std::vector<Point>::const_iterator xs_begin,
                               std::vector<Point>::const_iterator xs_end,
                               std::vector<Point>* tmp) {
    size_t n = xs_end - xs_begin;
    if (n <= 3) {                          /* brute force */
        double best = std::numeric_limits<double>::max();
        for (size_t i = 0; i < n; ++i) {
            for (size_t j = i + 1; j < n; ++j) {
                double d = dist(xs_begin[i], xs_begin[j]);
                if (d < best) best = d;
            }
        }
        std::sort(xs_begin, xs_end, [](const Point& a, const Point& b){ return a.y < b.y; });
        return best;
    }

    auto mid = xs_begin + n / 2;
    double midx = mid->x;

    double d1, d2;
    #pragma omp task shared(tmp) if (n > 1000) // parallelize large problems
    d1 = closest_pair_rec(xs_begin, mid, tmp);
    #pragma omp task shared(tmp) if (n > 1000)
    d2 = closest_pair_rec(mid, xs_end, tmp);
    #pragma omp taskwait
    double dmin = std::min(d1, d2);

    /* Merge by y-coordinate */
    std::inplace_merge(xs_begin, mid, xs_end, [](const Point& a, const Point& b){ return a.y < b.y; });

    /* Build strip */
    std::vector<Point> strip;
    strip.reserve(n);
    for (auto it = xs_begin; it != xs_end; ++it) {
        if (std::abs(it->x - midx) < dmin) strip.push_back(*it);
    }

    /* Check strip */
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < dmin; ++j) {
            double d = dist(strip[i], strip[j]);
            if (d < dmin) dmin = d;
        }
    }

    return dmin;
}

double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    /* Sort by x-coordinate */
    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> tmp;
    double result;
    #pragma omp parallel
    #pragma omp single
    {
        result = closest_pair_rec(pts.begin(), pts.end(), &tmp);
    }
    return result;
}
