#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Matrix multiplication: C += A * B
 * A: MxK, B: KxN, C: MxN (row-major)
 *
 * Optimised for x86‑64 with OpenMP and
 * a cache‑friendly blocking scheme.
 */
inline void gemm(const std::vector<double>& A,
                 const std::vector<double>& B,
                 std::vector<double>& C,
                 size_t M, size_t K, size_t N)
{
    // Block sizes tuned for a typical L2/L3 cache
    const size_t BLOCK_M = 64; // rows of A & C
    const size_t BLOCK_K = 64; // columns of A / rows of B
    const size_t BLOCK_N = 256; // columns of B & C

    // Parallelise over outermost blocks
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK_M) {
        size_t i_max = std::min(ii + BLOCK_M, M);

        for (size_t kk = 0; kk < K; kk += BLOCK_K) {
            size_t k_max = std::min(kk + BLOCK_K, K);

            for (size_t jj = 0; jj < N; jj += BLOCK_N) {
                size_t j_max = std::min(jj + BLOCK_N, N);

                for (size_t i = ii; i < i_max; ++i) {
                    const double* a_row = &A[i * K + kk];
                    double*       c_row = &C[i * N + jj];

                    for (size_t k = kk; k < k_max; ++k) {
                        const double aik = a_row[k - kk];
                        const double* b_col = &B[k * N + jj];

                        // Inner j loop unrolled for higher throughput
                        size_t j = jj;
                        for (; j + 3 < j_max; j += 4) {
                            c_row[j    ] += aik * b_col[j - jj];
                            c_row[j + 1] += aik * b_col[j + 1 - jj];
                            c_row[j + 2] += aik * b_col[j + 2 - jj];
                            c_row[j + 3] += aik * b_col[j + 3 - jj];
                        }
                        for (; j < j_max; ++j) {
                            c_row[j] += aik * b_col[j - jj];
                        }
                    }
                }
            }
        }
    }
}
