    std::vector<double> A_c = A;
    std::vector<double> b_c = b;
    x.resize(N);

    /* Forward elimination with partial pivoting (no row swaps for speed,
       the original algorithm skips if pivot==0). */

    for (size_t i = 0; i + 1 < N; ++i) {
        double pivot = A_c[i * N + i];
        if (pivot == 0.0) return;               // singular / zero pivot: abort

        #pragma omp parallel for schedule(static)  // parallelize the inner loop
        for (long long j = i + 1; j < static_cast<long long>(N); ++j) {
            double factor = A_c[j * N + i] / pivot;
            double* restrict row_j   = &A_c[j * N];
            double* restrict row_i   = &A_c[i * N];
            // Update the rest of the pivot row
            for (size_t k = i; k < N; ++k) {
                row_j[k] -= factor * row_i[k];
            }
            // Update the RHS
            b_c[j] -= factor * b_c[i];
        }
    }

    /* Back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double* row = &A_c[i * N];
        for (size_t j = i + 1; j < N; ++j) {
            sum += row[j] * x[j];
        }
        x[i] = (b_c[i] - sum) / A_c[i * N + i];
    }
}
