   preserves the exact semantics of the reference code, and is fully
   parallelised with OpenMP.  */
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    // Copy input (inside the function to avoid modifying the caller's vector)
    output = x;
    const std::size_t N = output.size();

    if (N <= 1) return;                     // trivial

    // ----- 1. Bit‑reversal permutation ------------------------------------
    // Compute reversal masks only once per size.  Because the function
    // may be called many times with the same N, we cache the permutation.
    static std::vector<std::vector<std::size_t>> rev_cache;
    static std::size_t last_N = 0;
    if (N != last_N) {                       // rebuild cache for new size
        last_N = N;
        rev_cache.resize(1);
        rev_cache[0].resize(N);
        std::size_t m = 0, tmp = N;
        while ((tmp >>= 1)) ++m;             // m = log2(N)
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t rev = 0;
            std::size_t x = i;
            for (std::size_t j = 0; j < m; ++j) {
                rev = (rev << 1) | (x & 1);
                x >>= 1;
            }
            rev_cache[0][i] = rev;
        }
    }

    std::vector<std::size_t> const& rev = rev_cache[0];
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i)
            std::swap(output[i], output[j]);
    }

    // ----- 2. Iterative FFT ------------------------------------------------
    // Pre‑compute twiddle factors once per stage.
    const double pi = 3.14159265358979323846264338328L;
    for (std::size_t len = 2; len <= N; len <<= 1) {
        const std::size_t half = len >> 1;
        const double step = -pi / half;
        // One twiddle per butterfly in this stage
        std::vector<std::complex<double>> wlen(half);
        for (std::size_t i = 0; i < half; ++i) {
            double ang = step * i;
            wlen[i] = std::complex<double>(std::cos(ang), std::sin(ang));
        }

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += len) {
            for (std::size_t j = 0; j < half; ++j) {
                std::complex<double> u = output[i + j];
                std::complex<double> v = output[i + j + half] * wlen[j];
                output[i + j] = u + v;
                output[i + j + half] = u - v;
            }
        }
    }
