/*
 * Optimised matrix–vector product.
 *
 * y = A * x
 *
 * A : MxN matrix in row‑major order
 * x : N elements
 * y : M elements (output)
 *
 * The routine is fully equivalent to the reference implementation but uses
 * blocking, spatial locality, and OpenMP multithreading to maximise
 * throughput on a modern x86‑64 CPU (8 hardware threads).
 */
inline void gemv(const std::vector<double>& A,
                 const std::vector<double>& x,
                 std::vector<double>& y,
                 std::size_t M, std::size_t N)
{
    const std::size_t block_row = 64;  // cache‑friendly block size
    const std::size_t block_col = 64;  // should be a multiple of SIMD width

    // Ensure output array has the right size
    y.resize(M);

    #pragma omp parallel for schedule(static, 8)
    for (std::size_t i0 = 0; i0 < M; i0 += block_row) {
        const std::size_t i_end = std::min(i0 + block_row, M);

        for (std::size_t j0 = 0; j0 < N; j0 += block_col) {
            const std::size_t j_end = std::min(j0 + block_col, N);

            for (std::size_t i = i0; i < i_end; ++i) {
                double sum = 0.0;
                const double*  a_row = &A[i * N + j0];
                const double*  x_ptr = &x[j0];
                std::size_t j = j0;

                // Unroll inner loop for better vectorisation
                for (; j + 7 < j_end; j += 8) {
                    sum += a_row[j - j0] * x_ptr[0];
                    sum += a_row[j - j0 + 1] * x_ptr[1];
                    sum += a_row[j - j0 + 2] * x_ptr[2];
                    sum += a_row[j - j0 + 3] * x_ptr[3];
                    sum += a_row[j - j0 + 4] * x_ptr[4];
                    sum += a_row[j - j0 + 5] * x_ptr[5];
                    sum += a_row[j - j0 + 6] * x_ptr[6];
                    sum += a_row[j - j0 + 7] * x_ptr[7];
                    x_ptr += 8;
                }
                for (; j < j_end; ++j) {
                    sum += a_row[j - j0] * x_ptr[0];
                    ++x_ptr;
                }
                y[i] += sum;
            }
        }
    }
