struct Result {
    int   startTime;
    int   duration;
    float value;
};

// Optimised parallel quick‑sort (OpenMP) for vectors of Result.
// Works with gcc -fopenmp.  The implementation falls back to
// std::sort for small partitions, ensuring identical final order.
inline void quickSort(std::vector<Result>& a, int left, int right) {
    constexpr int cutoff = 256;          // below this size we use std::sort
    if (right - left <= cutoff) {
        std::sort(a.begin() + left, a.begin() + right + 1,
                  [](const Result& x, const Result& y) { return x.startTime < y.startTime; });
        return;
    }

    // Hoare partition
    int i = left - 1, j = right + 1;
    int pivot = a[left + (right - left) / 2].startTime;

    while (true) {
        do ++i; while (a[i].startTime < pivot);
        do --j; while (a[j].startTime > pivot);
        if (i >= j) break;
        std::swap(a[i], a[j]);
    }

    // Recurse on smaller side first to keep recursion depth shallow
    int mid = j;
    if (mid - left < right - (mid + 1)) {
        quickSort(a, left, mid);
#pragma omp task shared(a) if (right - mid > cutoff)
        quickSort(a, mid + 1, right);
    } else {
        quickSort(a, mid + 1, right);
#pragma omp task shared(a) if (mid - left > cutoff)
        quickSort(a, left, mid);
    }
}

inline void sortByStartTime(std::vector<Result>& results) {
#pragma omp parallel
    {
#pragma omp single nowait
        quickSort(results, 0, static_cast<int>(results.size()) - 1);
    }
}
