/*  Parallel quick‑sort for complex numbers sorted by magnitude.
    The implementation keeps the exact semantics of the original
    single‑threaded std::sort but uses OpenMP to split the work
    across the available 8 threads.
*/
inline void quicksort_complex(std::vector<std::complex<double>>& a,
                              int left, int right,
                              int depth = 0)
{
    if (left >= right) return;

    // Cut‑off for small sub‑arrays – use std::inplace_merge
    if (right - left < 32) {
        std::sort(a.begin() + left, a.begin() + right + 1,
                  [](auto const& x, auto const& y) {
                      return std::abs(x) < std::abs(y);
                  });
        return;
    }

    // Median-of-three pivot
    int mid = (left + right) / 2;
    auto pivot = a[mid];
    double pivotMag = std::abs(pivot);
    std::swap(a[mid], a[right]);

    int i = left;
    for (int j = left; j < right; ++j) {
        if (std::abs(a[j]) < pivotMag) {
            std::swap(a[i++], a[j]);
        }
    }
    std::swap(a[i], a[right]);

    // Recursively sort the two partitions.
    // Parallelise only when depth is small to avoid too many tasks.
    if (depth < 4) {
#pragma omp task default(none) shared(a) if (i-1 > left) \
        firstprivate(left, i, depth)
        quicksort_complex(a, left, i - 1, depth + 1);
#pragma omp task default(none) shared(a) if (i+1 < right) \
        firstprivate(i, right, depth)
        quicksort_complex(a, i + 1, right, depth + 1);
#pragma omp taskwait
    } else {
        quicksort_complex(a, left, i - 1, depth + 1);
        quicksort_complex(a, i + 1, right, depth + 1);
    }
}

inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    if (x.empty() || x.size() == 1) return;

#pragma omp parallel
    {
#pragma omp single nowait
        quicksort_complex(x, 0, static_cast<int>(x.size()) - 1);
    }
}
