// Compute the forward FFT of a vector of N = 2^m complex numbers, in place.
// The algorithm is iterative, radix‑2, Cooley‑Tukey.
// The implementation uses precomputed twiddle factors and a lookup table for bit‑reversal,
// and it parallelises the innermost butterfly loop with OpenMP.
static void fft_helper(std::vector<std::complex<double>> &x)
{
    const std::size_t N = x.size();
    const std::size_t logN = static_cast<std::size_t>(std::countr_zero(N));   // N is power of two

    // ---------- Bit‑reversal permutation ----------
    // Pre‑compute the bit‑reversed indices.  Only the first N/2 entries are needed.
    static std::vector<std::size_t> revIdx;
    if (revIdx.size() < N) {
        revIdx.resize(N);
        for (std::size_t i = 0; i < N; ++i) {
            std::size_t v = i;
            std::size_t r = 0;
            for (std::size_t b = 0; b < logN; ++b) {
                r = (r << 1) | (v & 1);
                v >>= 1;
            }
            revIdx[i] = r;
        }
    }

    // Perform the permutation in place
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = revIdx[i];
        if (j > i && j < N) {
            std::swap(x[i], x[j]);
        }
    }

    // ---------- Precompute twiddle factors ----------
    std::vector<std::complex<double>> W(N / 2);
    for (std::size_t k = 0; k < N / 2; ++k) {
        double angle = -2.0 * M_PI * k / double(N);
        W[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    // ---------- Radix‑2 iterative FFT ----------
    // stage s uses sub‑transforms of length L = 2^s
    for (std::size_t s = 1; s <= logN; ++s) {
        std::size_t L  = 1ULL << s;           // current sub‑transform length
        std::size_t stride = N / L;           // spacing between taps in twiddle table

        // Parallelise the butterfly loops with OpenMP
#pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += L) {
            for (std::size_t j = 0; j < L/2; ++j) {
                std::size_t pos = k + j;
                std::complex<double> t = x[pos + L/2] * W[j * stride];
                x[pos + L/2] = x[pos] - t;
                x[pos]        += t;
            }
        }
    }
}

// Compute the inverse Fourier transform of x in-place.
// The algorithm uses the property F⁻¹(x) = conjugate(F(conjugate(x))) / N,
// therefore the function reuses fft_helper().
void ifft(std::vector<std::complex<double>> &x)
{
    // conjugate all elements
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double> &v) { return std::conj(v); });

    // forward FFT on the conjugated data
    fft_helper(x);

    // conjugate again
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double> &v) { return std::conj(v); });

    // divide by N
    const double invN = 1.0 / static_cast<double>(x.size());
#pragma omp parallel for
    for (std::size_t i = 0; i < x.size(); ++i) {
        x[i] *= invN;
    }
}
