#if defined(__AVX2__) && defined(__x86_64__)
constexpr bool use_avx2 = true;
#else
constexpr bool use_avx2 = false;
#endif

// Helper: compare 8 ints with a single target using AVX2
static inline bool avx2_contains(const int* data, std::size_t n, int target) {
    const std::size_t step = 8;             // 8 ints per AVX2 vector
    const __m256i v_target = _mm256_set1_epi32(target);

    std::size_t i = 0;
    for (; i + step <= n; i += step) {
        // Load 8 ints
        const __m256i vec = _mm256_load_si256(reinterpret_cast<const __m256i*>(data + i));
        // Compare element‑wise
        const __m256i mask = _mm256_cmpeq_epi32(vec, v_target);
        // If any comparison is true, the mask will contain a non‑zero element
        if (_mm256_movemask_epi8(mask)) return true;
    }
    // Handle remaining elements
    for (; i < n; ++i) {
        if (data[i] == target) return true;
    }
    return false;
}

// Main public API
inline bool contains(const std::vector<int>& x, int target) {
    // Fast path: empty vector
    if (x.empty()) return false;

    // Use AVX2 if available and vector is large enough
    if constexpr (use_avx2 && x.size() >= 16) { // at least two 8‑int blocks
        return avx2_contains(x.data(), x.size(), target);
    }

    // Fallback to simple scalar loop (branchless style)
    const int* data = x.data();
    const std::size_t n = x.size();
    std::size_t i = 0;
    for (; i + 4 <= n; i += 4) {
        // Unroll 4 comparisons
        if (data[i]   == target) return true;
        if (data[i+1] == target) return true;
        if (data[i+2] == target) return true;
        if (data[i+3] == target) return true;
    }
    for (; i < n; ++i) {
        if (data[i] == target) return true;
    }
    return false;
}
